/* oms-master-holidayBatch-sql-oracle.xml - insertHolidayInfo */
INSERT INTO TORDER_MST_HOLIDAY (
	  HOLIDAY
	, HOLINM
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
) VALUES (
	  #{locdate}
	, #{dateName}
	, #{sysdate}
	, #{interfaceUrkey}
	, #{sysdate}
	, #{interfaceUrkey}
)
ON CONFLICT (HOLIDAY)
DO UPDATE SET
	  HOLINM      = EXCLUDED.HOLINM
	, UPDATEDATE  = EXCLUDED.UPDATEDATE
	, UPDATEURKEY = EXCLUDED.UPDATEURKEY
